#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>

typedef struct {
    long long *data;
    int size;
    int capacity;
} MinHeap;

MinHeap* createHeap(int cap) {
    MinHeap *h = (MinHeap*)malloc(sizeof(MinHeap));
    h->data = (long long*)malloc(sizeof(long long)*(cap+1));
    h->size = 0;
    h->capacity = cap;
    return h;
}

void push(MinHeap *h, long long x) {
    int i = ++h->size;
    while(i>1 && h->data[i/2] > x) {
        h->data[i] = h->data[i/2];
        i/=2;
    }
    h->data[i] = x;
}

long long pop(MinHeap *h) {
    long long ret = h->data[1];
    long long x = h->data[h->size--];
    int i = 1;
    while(i*2 <= h->size) {
        int child = i*2;
        if(child+1 <= h->size && h->data[child+1] < h->data[child]) child++;
        if(h->data[child] >= x) break;
        h->data[i] = h->data[child];
        i = child;
    }
    h->data[i] = x;
    return ret;
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        MinHeap *h = createHeap(N);
        for(int i=0;i<N;i++){
            long long v; scanf("%lld", &v);
            push(h, v);
        }
        long long ans = 0;
        while(h->size > 1){
            long long a = pop(h);
            long long b = pop(h);
            long long s = a + b;
            ans += s;
            push(h, s);
        }
        printf("%lld\n", ans);
        free(h->data);
        free(h);
    }
    return 0;
}

