            int N = Integer.parseInt(br.readLine().trim());
            st = new StringTokenizer(br.readLine());
            PriorityQueue<Long> pq = new PriorityQueue<>();
            for (int i = 0; i < N; i++) {
                pq.add(Long.parseLong(st.nextToken()));
            }
            long ans = 0;
            while (pq.size() > 1) {
                long a = pq.poll();
                long b = pq.poll();
                long s = a + b;
                ans += s;
                pq.add(s);
            }
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

